using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Audio;

/// <summary>
/// Singleton central de áudio: música de fundo (BGM), som ambiente (BGS) e
/// efeitos sonoros (SE). Segue o mesmo padrão de WorldState/PlayerProgress
/// (Instance, DontDestroyOnLoad, criado automaticamente se não existir na cena).
///
/// - BGM e BGS têm cada um dois AudioSources internos para permitir crossfade
///   (transição suave entre uma música/ambiente e outro).
/// - SE usa uma pequena pool de AudioSources para tocar vários sons em
///   simultâneo sem cortar uns aos outros.
/// - Volumes (master/bgm/bgs/se, 0-1) são opcionalmente persistidos em
///   PlayerPrefs, prontos a ligar a um menu de opções.
/// - MusicZone (Etapa 3) regista-se aqui para mudar o BGM/BGS automaticamente
///   conforme a área onde o player está.
///
/// <para><b>Audio Mixer (Tarefa #19, opcional):</b> se <see cref="mixer"/>
/// estiver definido, os volumes master/bgm/bgs/se deixam de escalar
/// directamente "AudioSource.volume" e passam a controlar os parâmetros
/// expostos do Mixer (<see cref="masterVolumeParam"/>/<see cref="bgmVolumeParam"/>/
/// <see cref="bgsVolumeParam"/>/<see cref="seVolumeParam"/>, em dB — conversão
/// logarítmica a partir do valor 0-1), e as fontes de BGM/BGS/SE são roteadas
/// para <see cref="bgmGroup"/>/<see cref="bgsGroup"/>/<see cref="seGroup"/>.
/// Isto permite desenhar ducking, efeitos e snapshots na janela "Audio Mixer"
/// do Unity, sem código adicional. O filtro "memória" do Menu de Pausa
/// (<see cref="SetBgmMuffled"/>) passa a usar
/// <see cref="normalSnapshot"/>/<see cref="pausedSnapshot"/>
/// (AudioMixerSnapshot.TransitionTo) em vez do AudioLowPassFilter por código.</para>
///
/// <para>Sem "mixer" definido (campo vazio, predefinição): funciona
/// exactamente como antes — os volumes escalam "AudioSource.volume"
/// directamente, e a "memória" usa AudioLowPassFilter. Totalmente opcional e
/// compatível com cenas sem mixer configurado.</para>
///
/// <para><b>Configuração do AudioMixer no Unity (uma vez):</b></para>
/// <para>1. "Assets &gt; Create &gt; Audio Mixer" — criar o asset (ex: "MainMixer").</para>
/// <para>2. Na janela "Audio Mixer", criar 3 grupos dentro de "Master": "BGM", "BGS", "SE".</para>
/// <para>3. Em cada grupo ("Master", "BGM", "BGS", "SE"), botão direito no
/// slider "Volume" → "Expose ... to script", depois na aba "Exposed
/// Parameters" (canto superior direito) renomear cada parâmetro exposto para
/// "MasterVolume", "BGMVolume", "BGSVolume", "SEVolume" respectivamente — os
/// mesmos nomes (por defeito) de <see cref="masterVolumeParam"/> etc.</para>
/// <para>4. Criar duas Snapshots (painel "Snapshots"): "Normal" e "Pausado".
/// Seleccionar "Pausado" e, no grupo "BGM", reduzir o volume e/ou adicionar um
/// efeito "Lowpass" — este é o efeito "memória" do Menu de Pausa.</para>
/// <para>5. No Inspector do AudioManager: arrastar o asset para <see cref="mixer"/>,
/// os 3 grupos para <see cref="bgmGroup"/>/<see cref="bgsGroup"/>/<see cref="seGroup"/>,
/// e as 2 snapshots para <see cref="normalSnapshot"/>/<see cref="pausedSnapshot"/>.</para>
/// </summary>
public class AudioManager : MonoBehaviour
{
    public static AudioManager Instance { get; private set; }

    [Header("Volumes (0-1)")]
    [Range(0f, 1f)] [SerializeField] private float masterVolume = 1f;
    [Range(0f, 1f)] [SerializeField] private float bgmVolume = 1f;
    [Range(0f, 1f)] [SerializeField] private float bgsVolume = 1f;
    [Range(0f, 1f)] [SerializeField] private float seVolume = 1f;

    [Header("Sound Effects")]
    [Tooltip("Número de AudioSources usados para tocar SE em simultâneo.")]
    [SerializeField] private int sePoolSize = 8;

    [Header("Music Zones")]
    [Tooltip("Tempo de fade quando nenhuma zona activa define um clip para o canal (BGM ou BGS).")]
    [SerializeField] private float noZoneFadeTime = 1.5f;

    [Header("Persistência")]
    [Tooltip("Se activo, os volumes são lidos/guardados em PlayerPrefs.")]
    [SerializeField] private bool persistVolumes = true;

    [Header("Menu de Pausa — Filtro \"Memória\"")]
    [Tooltip("Frequência de corte (Hz) do filtro low-pass aplicado ao BGM enquanto o Menu de Pausa está aberto — \"como se o jogador estivesse a ouvir o mundo através de uma memória\". Usado apenas se 'normalSnapshot'/'pausedSnapshot' não estiverem definidos (fallback sem mixer). Não pára a música, só a abafa.")]
    [SerializeField] private float pausedBgmCutoff = 700f;

    [Header("Audio Mixer (opcional, Tarefa #19)")]
    [Tooltip("AudioMixer com grupos Master > BGM/BGS/SE e parâmetros expostos para os volumes. Se vazio, o AudioManager funciona sem mixer (como antes desta tarefa) — ver resumo na documentação da classe.")]
    [SerializeField] private AudioMixer mixer;

    [Tooltip("Nome do parâmetro exposto (Expose Parameter) para o volume geral, em dB.")]
    [SerializeField] private string masterVolumeParam = "MasterVolume";
    [Tooltip("Nome do parâmetro exposto para o volume da BGM, em dB.")]
    [SerializeField] private string bgmVolumeParam = "BGMVolume";
    [Tooltip("Nome do parâmetro exposto para o volume do BGS, em dB.")]
    [SerializeField] private string bgsVolumeParam = "BGSVolume";
    [Tooltip("Nome do parâmetro exposto para o volume dos SE, em dB.")]
    [SerializeField] private string seVolumeParam = "SEVolume";

    [Tooltip("Grupo do Mixer para as fontes de BGM (crossfade). Requer 'mixer'.")]
    [SerializeField] private AudioMixerGroup bgmGroup;
    [Tooltip("Grupo do Mixer para as fontes de BGS (crossfade). Requer 'mixer'.")]
    [SerializeField] private AudioMixerGroup bgsGroup;
    [Tooltip("Grupo do Mixer para a pool de SE. Requer 'mixer'.")]
    [SerializeField] private AudioMixerGroup seGroup;

    [Tooltip("Snapshot \"normal\" do Mixer (sem efeitos do Menu de Pausa). Requer 'mixer'.")]
    [SerializeField] private AudioMixerSnapshot normalSnapshot;
    [Tooltip("Snapshot do Menu de Pausa — efeito \"memória\" (ex: low-pass/volume reduzido no grupo BGM), configurado na janela Audio Mixer do Unity. Requer 'mixer'.")]
    [SerializeField] private AudioMixerSnapshot pausedSnapshot;
    [Tooltip("Duração da transição entre snapshots ao abrir/fechar o Menu de Pausa.")]
    [SerializeField] private float snapshotTransitionTime = 0.3f;

    private const string PrefMaster = "audio_master_volume";
    private const string PrefBgm = "audio_bgm_volume";
    private const string PrefBgs = "audio_bgs_volume";
    private const string PrefSe = "audio_se_volume";

    private AudioChannel _bgmChannel;
    private AudioChannel _bgsChannel;

    private AudioSource _bgmSourceA;
    private AudioSource _bgmSourceB;
    private bool _bgmMuffled;

    private AudioSource[] _sePool;
    private int _seNextIndex;

    private readonly List<MusicZone> _activeZones = new List<MusicZone>();

    public float MasterVolume => masterVolume;
    public float BgmVolume => bgmVolume;
    public float BgsVolume => bgsVolume;
    public float SeVolume => seVolume;

    public AudioClip CurrentBgmClip => _bgmChannel?.CurrentClip;
    public AudioClip CurrentBgsClip => _bgsChannel?.CurrentClip;

    private float EffectiveBgmVolume => bgmVolume * masterVolume;
    private float EffectiveBgsVolume => bgsVolume * masterVolume;
    private float EffectiveSeVolume => seVolume * masterVolume;

    /// <summary>
    /// Volume-alvo do AudioSource activo de BGM durante o crossfade. Com
    /// mixer configurado, o grupo "BGM" já aplica master/bgm em dB, pelo que
    /// a fonte toca a 1 (cheio); sem mixer, a fonte aplica directamente
    /// <see cref="EffectiveBgmVolume"/> (comportamento anterior).
    /// </summary>
    private float BgmCrossfadeTarget => mixer != null ? 1f : EffectiveBgmVolume;

    /// <summary>Equivalente a <see cref="BgmCrossfadeTarget"/> para o canal de BGS.</summary>
    private float BgsCrossfadeTarget => mixer != null ? 1f : EffectiveBgsVolume;

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons"). Sem isto, um
    /// AudioManager configurado numa cena (volumes/sePoolSize/etc. no
    /// Inspector) seria destruído ao encontrar a versão vazia auto-criada como
    /// Instance.
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        if (persistVolumes) LoadVolumes();

        SetupSources();
        ApplyAllVolumesToMixer();
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(AudioManager) + " (Fallback)");
        var instance = go.AddComponent<AudioManager>();
        instance.isAutoFallback = true;
    }

    private void SetupSources()
    {
        _bgmSourceA = CreateSource("BGM A", bgmGroup, true);
        _bgmSourceB = CreateSource("BGM B", bgmGroup, true);
        _bgmChannel = new AudioChannel(this, _bgmSourceA, _bgmSourceB);

        _bgsChannel = new AudioChannel(this, CreateSource("BGS A", bgsGroup), CreateSource("BGS B", bgsGroup));

        _sePool = new AudioSource[Mathf.Max(1, sePoolSize)];
        for (int i = 0; i < _sePool.Length; i++)
            _sePool[i] = CreateSource($"SE {i}", seGroup);
    }

    private AudioSource CreateSource(string sourceName, AudioMixerGroup group = null, bool addLowPassFilter = false)
    {
        var go = new GameObject(sourceName);
        go.transform.SetParent(transform);

        var source = go.AddComponent<AudioSource>();
        source.loop = true;
        source.playOnAwake = false;
        source.volume = 0f;

        if (group != null) source.outputAudioMixerGroup = group;

        if (addLowPassFilter)
        {
            var lowPass = go.AddComponent<AudioLowPassFilter>();
            lowPass.cutoffFrequency = 22000f;
            lowPass.enabled = false;
        }

        return source;
    }

    // ---------------- BGM ----------------

    /// <summary>Toca uma música de fundo, com crossfade. clip == null equivale a StopBGM.</summary>
    public void PlayBGM(AudioClip clip, float fadeTime = 1f, bool loop = true)
    {
        _bgmChannel.Play(clip, fadeTime, loop, BgmCrossfadeTarget);
    }

    /// <summary>Pára a música de fundo actual com fade-out.</summary>
    public void StopBGM(float fadeTime = 1f)
    {
        _bgmChannel.Stop(fadeTime);
    }

    /// <summary>
    /// Activa/desactiva o efeito "memória" no BGM (Menu de Pausa — Tarefa #6):
    /// abafa a música da área sem a parar, "como se o jogador estivesse a
    /// ouvir o mundo através de uma memória". Não afecta BGS nem SE.
    ///
    /// Com mixer e <see cref="normalSnapshot"/>/<see cref="pausedSnapshot"/>
    /// configurados (Tarefa #19), faz a transição entre snapshots do Mixer;
    /// caso contrário usa o filtro low-pass por código (comportamento anterior).
    /// </summary>
    public void SetBgmMuffled(bool muffled)
    {
        if (_bgmMuffled == muffled) return;
        _bgmMuffled = muffled;

        if (mixer != null && normalSnapshot != null && pausedSnapshot != null)
        {
            (muffled ? pausedSnapshot : normalSnapshot).TransitionTo(snapshotTransitionTime);
            return;
        }

        ApplyLowPass(_bgmSourceA, muffled);
        ApplyLowPass(_bgmSourceB, muffled);
    }

    private void ApplyLowPass(AudioSource source, bool enabled)
    {
        if (source == null) return;

        var lowPass = source.GetComponent<AudioLowPassFilter>();
        if (lowPass == null) return;

        lowPass.cutoffFrequency = pausedBgmCutoff;
        lowPass.enabled = enabled;
    }

    // ---------------- BGS ----------------

    /// <summary>Toca um som ambiente, com crossfade. clip == null equivale a StopBGS.</summary>
    public void PlayBGS(AudioClip clip, float fadeTime = 1f, bool loop = true)
    {
        _bgsChannel.Play(clip, fadeTime, loop, BgsCrossfadeTarget);
    }

    /// <summary>Pára o som ambiente actual com fade-out.</summary>
    public void StopBGS(float fadeTime = 1f)
    {
        _bgsChannel.Stop(fadeTime);
    }

    // ---------------- SE ----------------

    /// <summary>Toca um efeito sonoro uma vez (não-posicional), usando a pool de SE.</summary>
    /// <param name="volumeScale">Volume relativo deste som (0-1), multiplicado pelo volume de SE.</param>
    public void PlaySE(AudioClip clip, float volumeScale = 1f, float pitch = 1f)
    {
        if (clip == null || _sePool == null || _sePool.Length == 0) return;

        var source = _sePool[_seNextIndex];
        _seNextIndex = (_seNextIndex + 1) % _sePool.Length;

        source.pitch = pitch;
        source.volume = mixer != null ? 1f : EffectiveSeVolume;
        source.PlayOneShot(clip, Mathf.Clamp01(volumeScale));
    }

    /// <summary>
    /// Toca um efeito sonoro numa posição do mundo (útil para sons
    /// 3D/posicionais). Usa <see cref="AudioSource.PlayClipAtPoint"/>, que cria
    /// uma fonte temporária fora do Mixer — por isso aplica sempre
    /// <see cref="EffectiveSeVolume"/> directamente, mesmo com mixer configurado.
    /// </summary>
    public void PlaySEAtPoint(AudioClip clip, Vector3 position, float volumeScale = 1f)
    {
        if (clip == null) return;
        AudioSource.PlayClipAtPoint(clip, position, EffectiveSeVolume * Mathf.Clamp01(volumeScale));
    }

    // ---------------- Volumes ----------------

    public void SetMasterVolume(float value)
    {
        masterVolume = Mathf.Clamp01(value);
        ApplyMixerParam(masterVolumeParam, masterVolume);
        if (mixer == null)
        {
            _bgmChannel.SetActiveVolume(EffectiveBgmVolume);
            _bgsChannel.SetActiveVolume(EffectiveBgsVolume);
        }
        if (persistVolumes) PlayerPrefs.SetFloat(PrefMaster, masterVolume);
    }

    public void SetBgmVolume(float value)
    {
        bgmVolume = Mathf.Clamp01(value);
        ApplyMixerParam(bgmVolumeParam, bgmVolume);
        if (mixer == null) _bgmChannel.SetActiveVolume(EffectiveBgmVolume);
        if (persistVolumes) PlayerPrefs.SetFloat(PrefBgm, bgmVolume);
    }

    public void SetBgsVolume(float value)
    {
        bgsVolume = Mathf.Clamp01(value);
        ApplyMixerParam(bgsVolumeParam, bgsVolume);
        if (mixer == null) _bgsChannel.SetActiveVolume(EffectiveBgsVolume);
        if (persistVolumes) PlayerPrefs.SetFloat(PrefBgs, bgsVolume);
    }

    public void SetSeVolume(float value)
    {
        seVolume = Mathf.Clamp01(value);
        ApplyMixerParam(seVolumeParam, seVolume);
        if (persistVolumes) PlayerPrefs.SetFloat(PrefSe, seVolume);
    }

    private void LoadVolumes()
    {
        masterVolume = PlayerPrefs.GetFloat(PrefMaster, masterVolume);
        bgmVolume = PlayerPrefs.GetFloat(PrefBgm, bgmVolume);
        bgsVolume = PlayerPrefs.GetFloat(PrefBgs, bgsVolume);
        seVolume = PlayerPrefs.GetFloat(PrefSe, seVolume);
    }

    /// <summary>
    /// Envia os 4 volumes actuais (0-1) para os parâmetros expostos do Mixer,
    /// em dB. Chamado uma vez em <see cref="Awake"/> (depois de
    /// <see cref="LoadVolumes"/>) para sincronizar o Mixer com os valores
    /// persistidos/configurados. Sem efeito se <see cref="mixer"/> for nulo.
    /// </summary>
    private void ApplyAllVolumesToMixer()
    {
        ApplyMixerParam(masterVolumeParam, masterVolume);
        ApplyMixerParam(bgmVolumeParam, bgmVolume);
        ApplyMixerParam(bgsVolumeParam, bgsVolume);
        ApplyMixerParam(seVolumeParam, seVolume);
    }

    /// <summary>Converte um volume linear (0-1) para dB e aplica-o a um parâmetro exposto do Mixer. Sem efeito se <see cref="mixer"/> ou o nome do parâmetro estiverem vazios.</summary>
    private void ApplyMixerParam(string paramName, float linearValue)
    {
        if (mixer == null || string.IsNullOrEmpty(paramName)) return;
        mixer.SetFloat(paramName, LinearToDecibel(linearValue));
    }

    /// <summary>Conversão padrão linear→dB usada para volumes de AudioMixer (0 → -80dB "silêncio", 1 → 0dB).</summary>
    private static float LinearToDecibel(float value)
    {
        return value > 0.0001f ? Mathf.Log10(value) * 20f : -80f;
    }

    // ---------------- Music Zones ----------------

    /// <summary>Chamado por MusicZone quando o player entra na zona.</summary>
    public void RegisterZone(MusicZone zone)
    {
        if (zone == null || _activeZones.Contains(zone)) return;

        _activeZones.Add(zone);
        ApplyActiveZones();
    }

    /// <summary>Chamado por MusicZone quando o player sai da zona.</summary>
    public void UnregisterZone(MusicZone zone)
    {
        if (zone == null) return;
        if (!_activeZones.Remove(zone)) return;

        ApplyActiveZones();
    }

    /// <summary>
    /// Reavalia as zonas activas (BGM/BGS). Chamado por uma MusicZone quando
    /// uma das suas "conditions" (Etapa 8) muda de resultado enquanto o player
    /// continua dentro dela — sem isto, a zona só seria reavaliada ao entrar/
    /// sair (OnTriggerEnter2D/OnTriggerExit2D).
    /// </summary>
    public void RefreshActiveZones()
    {
        ApplyActiveZones();
    }

    /// <summary>
    /// Para BGM e BGS, escolhe — entre as zonas activas (com "conditions"
    /// cumpridas) que definem esse clip — a de maior prioridade, e toca-a. Se
    /// nenhuma zona activa definir esse clip, o canal é silenciado
    /// (StopBGM/StopBGS). Isto permite zonas "filhas" (ex: uma sala) só
    /// substituírem o BGS sem cortar a música da zona "mãe" (ex: a área
    /// inteira), bastando deixar bgmClip vazio na zona filha.
    /// </summary>
    private void ApplyActiveZones()
    {
        MusicZone bgmZone = null;
        MusicZone bgsZone = null;

        foreach (var zone in _activeZones)
        {
            if (zone == null || !zone.ConditionsMet()) continue;

            if (zone.bgmClip != null && (bgmZone == null || zone.priority > bgmZone.priority))
                bgmZone = zone;

            if (zone.bgsClip != null && (bgsZone == null || zone.priority > bgsZone.priority))
                bgsZone = zone;
        }

        if (bgmZone != null) PlayBGM(bgmZone.bgmClip, bgmZone.fadeTime, bgmZone.loop);
        else StopBGM(noZoneFadeTime);

        if (bgsZone != null) PlayBGS(bgsZone.bgsClip, bgsZone.fadeTime, bgsZone.loop);
        else StopBGS(noZoneFadeTime);
    }

    /// <summary>
    /// Canal de áudio com crossfade entre dois AudioSources. Usado internamente
    /// para BGM e BGS — o código é idêntico para os dois, só muda o volume-alvo.
    /// </summary>
    private class AudioChannel
    {
        private readonly MonoBehaviour _runner;
        private AudioSource _active;
        private AudioSource _standby;
        private Coroutine _fadeRoutine;

        public AudioClip CurrentClip { get; private set; }

        public AudioChannel(MonoBehaviour runner, AudioSource a, AudioSource b)
        {
            _runner = runner;
            _active = a;
            _standby = b;
        }

        /// <summary>Toca "clip" com crossfade. clip == null equivale a Stop().</summary>
        public void Play(AudioClip clip, float fadeTime, bool loop, float targetVolume)
        {
            if (clip == null) { Stop(fadeTime); return; }
            if (CurrentClip == clip && _active.isPlaying) return;

            CurrentClip = clip;

            _standby.clip = clip;
            _standby.loop = loop;
            _standby.volume = 0f;
            _standby.Play();

            if (_fadeRoutine != null) _runner.StopCoroutine(_fadeRoutine);
            _fadeRoutine = _runner.StartCoroutine(Crossfade(_active, _standby, fadeTime, targetVolume));

            (_active, _standby) = (_standby, _active);
        }

        /// <summary>Pára o clip actual com fade-out.</summary>
        public void Stop(float fadeTime)
        {
            if (CurrentClip == null && !_active.isPlaying) return;

            CurrentClip = null;

            if (_fadeRoutine != null) _runner.StopCoroutine(_fadeRoutine);
            _fadeRoutine = _runner.StartCoroutine(FadeOut(_active, fadeTime));
        }

        /// <summary>Ajusta o volume do source actualmente activo (ex: após mudar as opções de volume).</summary>
        public void SetActiveVolume(float volume)
        {
            if (_active != null && _active.isPlaying) _active.volume = volume;
        }

        private IEnumerator Crossfade(AudioSource from, AudioSource to, float fadeTime, float targetVolume)
        {
            if (fadeTime <= 0f)
            {
                to.volume = targetVolume;

                if (from != null)
                {
                    from.volume = 0f;
                    from.Stop();
                }

                yield break;
            }

            float fromStart = from != null ? from.volume : 0f;
            float t = 0f;

            while (t < fadeTime)
            {
                t += Time.unscaledDeltaTime;
                float ratio = Mathf.Clamp01(t / fadeTime);

                to.volume = Mathf.Lerp(0f, targetVolume, ratio);
                if (from != null) from.volume = Mathf.Lerp(fromStart, 0f, ratio);

                yield return null;
            }

            to.volume = targetVolume;

            if (from != null)
            {
                from.volume = 0f;
                from.Stop();
            }
        }

        private IEnumerator FadeOut(AudioSource source, float fadeTime)
        {
            if (source == null) yield break;

            float start = source.volume;

            if (fadeTime <= 0f)
            {
                source.volume = 0f;
                source.Stop();
                yield break;
            }

            float t = 0f;
            while (t < fadeTime)
            {
                t += Time.unscaledDeltaTime;
                source.volume = Mathf.Lerp(start, 0f, Mathf.Clamp01(t / fadeTime));
                yield return null;
            }

            source.volume = 0f;
            source.Stop();
        }
    }
}
